/**
 * WebAssembly bindings for spz2glb
 * Uses Emscripten-generated JS glue code with smart memory management
 */

// Import the Emscripten-generated module
// This will be loaded from spz2glb.js (generated by Emscripten)
let spz2glbModule = null;

async function initModule(wasmUrl, memoryOptions = {}) {
    if (spz2glbModule) return spz2glbModule;

    // Create memory with smart configuration
    const memory = new WebAssembly.Memory({
        initial: memoryOptions.initialPages || 64,  // 64 * 64KB = 4MB
        maximum: memoryOptions.maximumPages || 1024, // 1024 * 64KB = 64MB
    });

    // Load the Emscripten-generated JS glue code
    const response = await fetch(wasmUrl.replace('.wasm', '.js'));
    const jsCode = await response.text();

    // Create a module that uses our memory
    const moduleFactory = new Function('return ' + jsCode)();
    spz2glbModule = await moduleFactory({
        wasmMemory: memory,
        locateFile: (path) => {
            if (path.endsWith('.wasm')) return wasmUrl;
            return path;
        }
    });

    return spz2glbModule;
}

export async function loadSpz2Glb(wasmUrl, options = {}) {
    const module = await initModule(wasmUrl, options);

    return {
        validateHeader: (buffer) => {
            const ptr = module._spz2glb_alloc(buffer.length);
            module.HEAPU8.set(buffer, ptr);
            const result = module._spz2glb_validate_header(ptr, buffer.length);
            module._spz2glb_free(ptr);
            return result;
        },

        convert: (spzBuffer) => {
            const inputPtr = module._spz2glb_alloc(spzBuffer.length);
            module.HEAPU8.set(spzBuffer, inputPtr);

            const outSizePtr = module._spz2glb_alloc(4);
            const resultPtr = module._spz2glb_convert(inputPtr, spzBuffer.length, outSizePtr);

            module._spz2glb_free(inputPtr);

            if (!resultPtr) {
                module._spz2glb_free(outSizePtr);
                return null;
            }

            const outSize = module.HEAPU32[outSizePtr / 4];
            module._spz2glb_free(outSizePtr);

            if (!outSize) {
                module._spz2glb_free(resultPtr);
                return null;
            }

            const result = new Uint8Array(module.HEAPU8.slice(resultPtr, resultPtr + outSize));
            module._spz2glb_free(resultPtr);
            return result;
        },

        getVersion: () => {
            const ptr = module._spz2glb_alloc(12);
            module._spz2glb_get_version(ptr, ptr + 4, ptr + 8);
            const major = module.HEAPU32[ptr / 4];
            const minor = module.HEAPU32[ptr / 4 + 1];
            const patch = module.HEAPU32[ptr / 4 + 2];
            module._spz2glb_free(ptr);
            return `${major}.${minor}.${patch}`;
        }
    };
}
